SELECT 
    Aggregate(
        {
            [Sales Channel].[Sales Channel].&[Internet],
            [Sales Channel].[Sales Channel].&[Reseller]
        },
        [Measures].[Gross Profit Margin]
    ) ON COLUMNS
FROM [Adventure Works]

WITH MEMBER [Measures].[Internet Tax %] AS ([Measures].[Internet Tax Amount] / [Measures].[Internet Sales Amount]) * 100
SELECT [Measures].[Internet Tax %] ON COLUMNS
FROM [Adventure Works];
